var e=[{id:`L2_1`,type:`dialog`,speaker:null,text:{KOREA:`오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.`,JPN:`長い間悩んだ結果、あなたは一つ大事なことに気づいた。`,ENG:`After much debate, you came to the conclusion`,TWN:`苦惱許久後，你意識到一件重要的事實。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:null,text:{KOREA:`줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.`,JPN:`ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。`,ENG:`that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.`,TWN:`經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:null,text:{KOREA:`그리하여 당신은 결심했다.`,JPN:`そして、あなたは決心した。`,ENG:`So, you've decided`,TWN:`所以你下定決心。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:null,text:{KOREA:`이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.`,JPN:`この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。`,ENG:`that you'll be with her, no matter the consequences.`,TWN:`不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:null,text:{KOREA:`마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.`,JPN:`意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。`,ENG:`Having decided that, you called her to your office. She said she'd be here soon.`,TWN:`做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L12_1`,type:`dialog`,speaker:`JESSICA_RSEVEN_NULL_NULL`,text:{KOREA:`종신계약?`,JPN:`終身契約？`,ENG:`A lifetime contract?`,TWN:`終身契約？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`JESSICA_RSEVEN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`JESSICA_RSEVEN_NULL_NULL`,text:{KOREA:`......잠깐, 지금 진담이세요?`,JPN:`……待ってください。今、本気で言ってるんですか？`,ENG:`Wait, are you serious?`,TWN:`......等一下，你是說真的嗎？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`JESSICA_RSEVEN_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`JESSICA_RSEVEN_NULL_NULL`,text:{KOREA:`하아......`,JPN:`ふう……`,ENG:`*Sigh* `,TWN:`唉......`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`JESSICA_RSEVEN_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`JESSICA_RSEVEN_NULL_NULL`,text:{KOREA:`사장님, 이건 정말 걱정되서 하는 말인데요. 부탁이니 그런 제안은 좀 신중하게 하세요. 나중에 무슨 꿍꿍이를 품을지 누가 알겠어요?`,JPN:`社長、本当に心配だから言うんですが。お願いですから、こういう提案は慎重に進めてください。あとから何を企むか誰も知りませんよ。`,ENG:`Boss, I'm saying this because I'm really worried, but please be careful when you make such an offer. What if the other party tries to take advantage of you later?`,TWN:`老闆，我是真的是擔心你啦。算我拜託你吧，這種提議請慎重一點。誰知道以後對方會不會心懷鬼胎？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`JESSICA_RSEVEN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`JESSICA_RSEVEN_NULL_NULL`,text:{KOREA:`이러니 참...... 못 떠나겠다니까요. 지휘는 잘만 하시면서.`,JPN:`指揮能力が高いくせに、そんなことを言われると……離れられなくなるんですよ。`,ENG:`Gosh, this is why I can't leave you. You're only good at commanding, and nothing else.`,TWN:`這還真是......沒辦法離開了啊。況且你也指揮得很好。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`JESSICA_RSEVEN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`JESSICA_RSEVEN_NULL_NULL`,text:{KOREA:`계약서 이리 주세요.`,JPN:`私に契約書を渡してください。`,ENG:`Give me that contract.`,TWN:`把契約書給我吧。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`JESSICA_RSEVEN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`JESSICA_RSEVEN_NULL_NULL`,text:{KOREA:`회사는 걱정되고, 사장님 밑에 있으면 목숨은 건사할 것 같고. 어디까지나 그것뿐이에요.`,JPN:`会社も心配ですし、社長の下で働けば命を落とさなくて済みそうですし。あくまでそれだけです。`,ENG:`I'm just worried about this company, and I know I at least won't die if I work for you. That's all. `,TWN:`我很擔心這間公司，而且在老闆手下工作的話，應該可以保證生命安全，說到底就只是這樣而已。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`JESSICA_RSEVEN_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`JESSICA_RSEVEN_NULL_NULL`,text:{KOREA:`다른 뜻은 정말로 없으니까, 제 말 잘 알아들으셨죠?`,JPN:`決して他意はありませんよ。私の話、ご理解いただけましたよね？`,ENG:`I really have no other reason than that. Get it?`,TWN:`真的沒有別的意思，你有聽懂我說的話吧？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`JESSICA_RSEVEN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};